import React, { useEffect, useCallback } from 'react';
import { Linking, Alert } from 'react-native';
import { useNavigation } from '@react-navigation/native';

const DeepLinkHandler = () => {
  const navigation = useNavigation();

  const parseDeepLink = (url) => {
    if (!url) return null;

    const urlPattern = /^myapp:\/\/([^\/]+)(?:\/(.+))?$/;
    const match = url.match(urlPattern);

    if (!match) return null;

    const [, route, params] = match;
    return { route, params };
  };

  const handleDeepLink = useCallback((url) => {
    const parsed = parseDeepLink(url);

    if (!parsed) {
      Alert.alert('Invalid Link', 'The link you followed is not valid.');
      return;
    }

    const { route, params } = parsed;

    switch (route) {
      case 'profile':
        if (params) {
          navigation.navigate('Profile', { userId: params });
        } else {
          navigation.navigate('Profile');
        }
        break;

      case 'payment':
        if (params === 'confirm') {
          navigation.navigate('PaymentConfirmation');
        } else {
          navigation.navigate('Payment', { action: params });
        }
        break;

      case 'home':
        navigation.navigate('Home');
        break;

      case 'settings':
        navigation.navigate('Settings');
        break;

      case 'product':
        if (params) {
          navigation.navigate('ProductDetail', { productId: params });
        }
        break;

      case 'cart':
        navigation.navigate('Cart');
        break;

      case 'orders':
        if (params) {
          navigation.navigate('OrderDetail', { orderId: params });
        } else {
          navigation.navigate('Orders');
        }
        break;

      case 'notifications':
        navigation.navigate('Notifications');
        break;

      default:
        Alert.alert('Unknown Route', `The route "${route}" is not recognized.`);
        navigation.navigate('Home');
        break;
    }
  }, [navigation]);

  useEffect(() => {
    const handleInitialURL = async () => {
      try {
        const initialUrl = await Linking.getInitialURL();
        if (initialUrl) {
          handleDeepLink(initialUrl);
        }
      } catch (error) {
        console.error('Error getting initial URL:', error);
      }
    };

    handleInitialURL();

    const subscription = Linking.addEventListener('url', ({ url }) => {
      handleDeepLink(url);
    });

    return () => {
      subscription.remove();
    };
  }, [handleDeepLink]);

  return null;
};

export default DeepLinkHandler;

export const createDeepLink = (route, params = '') => {
  const baseUrl = 'myapp://';
  if (params) {
    return `${baseUrl}${route}/${params}`;
  }
  return `${baseUrl}${route}`;
};

export const openDeepLink = async (route, params = '') => {
  const url = createDeepLink(route, params);
  try {
    const supported = await Linking.canOpenURL(url);
    if (supported) {
      await Linking.openURL(url);
    } else {
      Alert.alert('Error', 'Cannot open this link');
    }
  } catch (error) {
    console.error('Error opening deep link:', error);
    Alert.alert('Error', 'Failed to open link');
  }
};

export const parseQueryParams = (url) => {
  const queryString = url.split('?')[1];
  if (!queryString) return {};

  return queryString.split('&').reduce((params, param) => {
    const [key, value] = param.split('=');
    params[decodeURIComponent(key)] = decodeURIComponent(value || '');
    return params;
  }, {});
};

export const AdvancedDeepLinkHandler = () => {
  const navigation = useNavigation();

  const parseAdvancedDeepLink = (url) => {
    if (!url) return null;

    const [baseUrl, queryString] = url.split('?');
    const urlPattern = /^myapp:\/\/([^\/]+)(?:\/([^?]+))?/;
    const match = baseUrl.match(urlPattern);

    if (!match) return null;

    const [, route, pathParams] = match;
    const queryParams = queryString ? parseQueryParams(url) : {};

    return { route, pathParams, queryParams };
  };

  const handleAdvancedDeepLink = useCallback((url) => {
    const parsed = parseAdvancedDeepLink(url);

    if (!parsed) {
      Alert.alert('Invalid Link', 'The link you followed is not valid.');
      return;
    }

    const { route, pathParams, queryParams } = parsed;

    switch (route) {
      case 'profile':
        navigation.navigate('Profile', {
          userId: pathParams,
          tab: queryParams.tab,
          referrer: queryParams.ref
        });
        break;

      case 'payment':
        if (pathParams === 'confirm') {
          navigation.navigate('PaymentConfirmation', {
            transactionId: queryParams.txn,
            status: queryParams.status
          });
        } else {
          navigation.navigate('Payment', {
            action: pathParams,
            amount: queryParams.amount,
            currency: queryParams.currency
          });
        }
        break;

      case 'product':
        navigation.navigate('ProductDetail', {
          productId: pathParams,
          variant: queryParams.variant,
          campaign: queryParams.campaign,
          source: queryParams.source
        });
        break;

      case 'promo':
        navigation.navigate('Promotion', {
          promoCode: pathParams,
          category: queryParams.category
        });
        break;

      case 'search':
        navigation.navigate('Search', {
          query: queryParams.q,
          category: queryParams.category,
          filters: queryParams.filters
        });
        break;

      default:
        navigation.navigate('Home', { deeplink: url });
        break;
    }
  }, [navigation]);

  useEffect(() => {
    const handleInitialURL = async () => {
      try {
        const initialUrl = await Linking.getInitialURL();
        if (initialUrl) {
          setTimeout(() => handleAdvancedDeepLink(initialUrl), 500);
        }
      } catch (error) {
        console.error('Error getting initial URL:', error);
      }
    };

    handleInitialURL();

    const subscription = Linking.addEventListener('url', ({ url }) => {
      handleAdvancedDeepLink(url);
    });

    return () => {
      subscription.remove();
    };
  }, [handleAdvancedDeepLink]);

  return null;
};

