export const useDeepLinkNavigation = () => {
  const navigation = useNavigation();

  const navigateToDeepLink = useCallback((url) => {
    const parsed = parseDeepLink(url);
    if (parsed) {
      handleDeepLink(url);
    }
  }, [navigation]);

  return { navigateToDeepLink };
};

